namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = "";
    public string Category { get; set; } = "";
    public string Description { get; set; } = "";
    public List<string> Ingredients { get; set; } = new();
    public List<string> Steps { get; set; } = new();
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }
    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private readonly object _lock = new();
    private int _nextId;

    public RecipeService()
    {
        _recipes = new List<Recipe>
        {
            new Recipe
            {
                Id = 1, Title = "Classic Pancakes", Category = "Breakfast",
                Description = "Fluffy golden pancakes perfect for a weekend morning.",
                Ingredients = new List<string> { "1 cup all-purpose flour", "2 eggs", "3/4 cup milk", "2 tbsp butter" },
                Steps = new List<string> { "Mix flour, eggs, and milk until smooth.", "Heat a buttered skillet over medium heat.", "Pour batter and cook until bubbles form, then flip." },
                TotalRatings = 3, RatingSum = 13
            },
            new Recipe
            {
                Id = 2, Title = "Avocado Toast", Category = "Breakfast",
                Description = "Simple and nutritious avocado toast with a hint of lemon.",
                Ingredients = new List<string> { "2 slices sourdough bread", "1 ripe avocado", "1 tbsp lemon juice", "Salt and pepper" },
                Steps = new List<string> { "Toast the bread until golden.", "Mash avocado with lemon juice, salt, and pepper.", "Spread onto toast and serve." },
                TotalRatings = 2, RatingSum = 9
            },
            new Recipe
            {
                Id = 3, Title = "Grilled Lemon Chicken", Category = "Dinner",
                Description = "Juicy grilled chicken marinated in lemon and herbs.",
                Ingredients = new List<string> { "4 chicken breasts", "2 lemons juiced", "3 cloves garlic minced", "2 tbsp olive oil" },
                Steps = new List<string> { "Marinate chicken in lemon juice, garlic, and olive oil for 30 minutes.", "Grill over medium-high heat for 6-7 minutes per side.", "Rest for 5 minutes before serving." },
                TotalRatings = 5, RatingSum = 22
            },
            new Recipe
            {
                Id = 4, Title = "Beef Stir Fry", Category = "Dinner",
                Description = "Quick and savory beef stir fry with fresh vegetables.",
                Ingredients = new List<string> { "1 lb beef sirloin sliced thin", "2 cups mixed vegetables", "3 tbsp soy sauce", "1 tbsp sesame oil" },
                Steps = new List<string> { "Heat sesame oil in a wok over high heat.", "Stir fry beef until browned, then add vegetables.", "Add soy sauce and cook for 2 more minutes." },
                TotalRatings = 4, RatingSum = 16
            },
            new Recipe
            {
                Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts",
                Description = "Rich and indulgent chocolate cake with a molten center.",
                Ingredients = new List<string> { "4 oz dark chocolate", "1/2 cup butter", "2 eggs", "1/4 cup sugar" },
                Steps = new List<string> { "Melt chocolate and butter together, then mix in eggs and sugar.", "Pour into greased ramekins and bake at 425°F for 12 minutes.", "Invert onto plates and serve immediately." },
                TotalRatings = 6, RatingSum = 28
            },
            new Recipe
            {
                Id = 6, Title = "Strawberry Cheesecake", Category = "Desserts",
                Description = "Creamy cheesecake topped with fresh strawberry glaze.",
                Ingredients = new List<string> { "16 oz cream cheese", "1/2 cup sugar", "2 eggs", "1 cup fresh strawberries" },
                Steps = new List<string> { "Beat cream cheese and sugar until smooth, then mix in eggs.", "Pour into a graham cracker crust and bake at 325°F for 45 minutes.", "Top with sliced strawberries and chill before serving." },
                TotalRatings = 3, RatingSum = 14
            }
        };
        _nextId = 7;
    }

    public List<string> GetCategories()
    {
        lock (_lock)
        {
            return _recipes.Select(r => r.Category).Distinct().ToList();
        }
    }

    public List<Recipe> GetRecipesByCategory(string category)
    {
        lock (_lock)
        {
            return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
        }
    }

    public Recipe? GetRecipe(int id)
    {
        lock (_lock)
        {
            return _recipes.FirstOrDefault(r => r.Id == id);
        }
    }

    public Recipe AddRecipe(Recipe recipe)
    {
        lock (_lock)
        {
            recipe.Id = _nextId++;
            _recipes.Add(recipe);
            return recipe;
        }
    }

    public void AddRating(int recipeId, int stars)
    {
        lock (_lock)
        {
            var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
            if (recipe != null)
            {
                recipe.TotalRatings++;
                recipe.RatingSum += stars;
            }
        }
    }
}

@page "/recipes"
@page "/recipes/{CategoryName}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>RecipeShare - Recipes</PageTitle>

@if (string.IsNullOrEmpty(CategoryName))
{
    <h1>All Categories</h1>
    <div class="row mt-3">
        @foreach (var category in RecipeService.GetCategories())
        {
            var recipes = RecipeService.GetRecipesByCategory(category);
            <div class="col-md-4 mb-3">
                <div class="card h-100">
                    <div class="card-body text-center">
                        <h5 class="card-title">@category</h5>
                        <p class="card-text">@recipes.Count recipe(s)</p>
                        <a href="recipes/@category" class="btn btn-outline-primary">Browse</a>
                    </div>
                </div>
            </div>
        }
    </div>
}
else
{
    <h1>@CategoryName Recipes</h1>
    <a href="recipes" class="btn btn-sm btn-outline-secondary mb-3">← All Categories</a>

    var recipes = RecipeService.GetRecipesByCategory(CategoryName);
    @if (recipes.Count == 0)
    {
        <p>No recipes found in this category.</p>
    }
    else
    {
        <div class="row">
            @foreach (var recipe in recipes)
            {
                <div class="col-md-6 mb-3">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text">@recipe.Description</p>
                            <p class="text-warning mb-2">★ @recipe.AverageRating.ToString("F1")</p>
                            <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter]
    public string? CategoryName { get; set; }
}

@page "/recipe/{Id:int}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>RecipeShare - Recipe</PageTitle>

@if (recipe is null)
{
    <p>Recipe not found.</p>
}
else
{
    <h1>@recipe.Title</h1>
    <span class="badge bg-secondary">@recipe.Category</span>
    <p class="mt-3">@recipe.Description</p>
    <p class="text-warning">Average Rating: ★ @recipe.AverageRating.ToString("F1") (@recipe.TotalRatings ratings)</p>

    <h3 class="mt-4">Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients)
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3 class="mt-4">Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps)
        {
            <li>@step</li>
        }
    </ol>

    <h3 class="mt-4">Rate this Recipe</h3>
    <StarRating RecipeId="Id" />
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnInitialized()
    {
        recipe = RecipeService.GetRecipe(Id);
    }
}

@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<div>
    <div class="star-rating">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star" @onclick="() => Rate(star)">
                @(star <= hoveredStar ? "★" : "☆")
            </span>
        }
    </div>
    <p class="mt-2">
        Average: ★ @averageRating.ToString("F1") (@totalRatings ratings)
    </p>
    @if (rated)
    {
        <p class="text-success">Thanks for your rating!</p>
    }
</div>

<style>
    .star-rating .star {
        font-size: 2rem;
        cursor: pointer;
        color: goldenrod;
    }
    .star-rating .star:hover {
        transform: scale(1.2);
    }
</style>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int hoveredStar;
    private bool rated;
    private double averageRating;
    private int totalRatings;

    protected override void OnInitialized()
    {
        LoadRating();
    }

    private void Rate(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        rated = true;
        hoveredStar = stars;
        LoadRating();
    }

    private void LoadRating()
    {
        var recipe = RecipeService.GetRecipe(RecipeId);
        if (recipe != null)
        {
            averageRating = recipe.AverageRating;
            totalRatings = recipe.TotalRatings;
        }
    }
}

@page "/submit"
@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>RecipeShare - Submit Recipe</PageTitle>

<h1>Submit a Recipe</h1>

@if (submittedRecipe is not null)
{
    <div class="alert alert-success">
        <strong>Recipe submitted successfully!</strong>
        <a href="recipe/@submittedRecipe.Id">View your recipe: @submittedRecipe.Title</a>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label class="form-label">Title</label>
            <InputText class="form-control" @bind-Value="model.Title" />
            <ValidationMessage For="() => model.Title" />
        </div>

        <div class="mb-3">
            <label class="form-label">Category</label>
            <InputSelect class="form-control" @bind-Value="model.Category">
                <option value="">-- Select --</option>
                <option value="Breakfast">Breakfast</option>
                <option value="Dinner">Dinner</option>
                <option value="Desserts">Desserts</option>
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => model.Category" />
        </div>

        <div class="mb-3">
            <label class="form-label">Description</label>
            <InputTextArea class="form-control" @bind-Value="model.Description" rows="2" />
        </div>

        <div class="mb-3">
            <label class="form-label">Ingredients (one per line)</label>
            <InputTextArea class="form-control" @bind-Value="model.IngredientsText" rows="4" />
        </div>

        <div class="mb-3">
            <label class="form-label">Steps (one per line)</label>
            <InputTextArea class="form-control" @bind-Value="model.StepsText" rows="4" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel model = new();
    private Recipe? submittedRecipe;

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = model.Title,
            Category = model.Category,
            Description = model.Description ?? "",
            Ingredients = ParseLines(model.IngredientsText),
            Steps = ParseLines(model.StepsText)
        };

        submittedRecipe = RecipeService.AddRecipe(recipe);
    }

    private List<string> ParseLines(string? text)
    {
        if (string.IsNullOrWhiteSpace(text)) return new();
        return text.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList();
    }

    public class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required.")]
        public string Category { get; set; } = "";

        public string? Description { get; set; }
        public string? IngredientsText { get; set; }
        public string? StepsText { get; set; }
    }
}

